import{_ as o,o as e,c as d,ah as r}from"./chunks/framework.BN3J8bM-.js";const m=JSON.parse('{"title":"使用平台组件","description":"","frontmatter":{},"headers":[],"relativePath":"使用平台组件.md","filePath":"使用平台组件.md"}'),n={name:"使用平台组件.md"};function c(a,t,s,i,h,l){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="使用平台组件" tabindex="-1">使用平台组件 <a class="header-anchor" href="#使用平台组件" aria-label="Permalink to &quot;使用平台组件&quot;">​</a></h1><p>在自定义组件中，除自研功能组件外，还可以 <strong>直接引用平台预置的业务功能组件</strong>（如实体列表、全局搜索组件等）。支持通过 <strong><code>import</code> 方式</strong> 在自定义组件中使用。</p><h2 id="使用说明" tabindex="-1">使用说明 <a class="header-anchor" href="#使用说明" aria-label="Permalink to &quot;使用说明&quot;">​</a></h2><ul><li><strong>使用方式</strong>：H5 端从 <strong><code>neo-ui-component-h5</code></strong> 导入，PC / Web 端从 <strong><code>neo-ui-component-web</code></strong> 导入。创建自定义组件时需通过 <code>neo create cmp</code> 的 <strong><code>--targetDevice</code>（或 <code>-d</code>）</strong> 选择对应终端类型，与运行环境一致。</li><li><strong>依赖注入</strong>：<strong>无需</strong>在工程 <code>package.json</code> 中安装上述模块（<code>neo-ui-component-h5</code>、<code>neo-ui-component-web</code>等）；在 Neo 平台（页面设计器 / 运行时）中由平台 <strong>注入</strong> 对应模块。</li><li><strong>渲染器</strong>：部分组件依赖 amis 子节点渲染，需传入框架注入的 <strong><code>this.props.render</code>（类组件）</strong> 或 <strong><code>props.render</code>（函数组件）</strong>，否则内部 Schema 无法正确渲染。详见各组件独立说明。</li></ul><h2 id="当前已支持的平台业务组件" tabindex="-1">当前已支持的平台业务组件 <a class="header-anchor" href="#当前已支持的平台业务组件" aria-label="Permalink to &quot;当前已支持的平台业务组件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>端</th><th>组件 / 封装名</th><th>包</th><th>说明文档</th></tr></thead><tbody><tr><td>H5</td><td><code>NeoEntityList</code>（基于 <code>EntityList</code>）</td><td><code>neo-ui-component-h5</code></td><td><a href="/cmpDocs/H5版列表组件使用说明.html">H5 版列表组件使用说明</a></td></tr><tr><td>H5</td><td><code>GlobalSearchInput</code></td><td><code>neo-ui-component-h5</code></td><td><a href="/cmpDocs/H5版全局搜索组件使用说明.html">H5 版全局搜索组件使用说明</a></td></tr><tr><td>Web（PC）</td><td><code>NeoEntityGrid</code>（基于 <code>EntityGrid</code>）</td><td><code>neo-ui-component-web</code></td><td><a href="/cmpDocs/PC版列表组件使用说明.html">PC 版列表组件使用说明</a></td></tr></tbody></table><p><strong>快速跳转：</strong></p><ul><li><a href="/cmpDocs/H5版列表组件使用说明.html">H5 端 — NeoEntityList 列表能力</a></li><li><a href="/cmpDocs/H5版全局搜索组件使用说明.html">H5 端 — GlobalSearchInput 全局搜索入口</a></li><li><a href="/cmpDocs/PC版列表组件使用说明.html">PC 端 — NeoEntityGrid 列表与网格</a></li></ul><p>与工程依赖、构建相关的通用约定，另见 <a href="/guide/组件开发规范.html#_10-复用平台预置依赖">自定义组件开发规范 - 10. 复用平台预置依赖</a> 中关于 <code>neo-ui-component-web</code> 等包名的说明。</p>',9)])])}const g=o(n,[["render",c]]);export{m as __pageData,g as default};
